$(function(){$("a.btn-insert-poem").on("click",function(){var t=$(this),e=$(".article-title").val(),n=new Date,a=Date.parse(n),i=$(".article-type").find("option:selected").val(),l=$("#elm1").val(),o=$(".article-author").val(),c=t.siblings(".notice-span"),r=$("#elm2").val(),s=$("#elm3").val();e.length>1&&l.length>1&&o.length>1&&r.length>1&&s.length>1?(c.html(""),$.getJSON("/insertpoem",{title:e,content:l,time:n.toLocaleString(),type:i,parse:a,author:o,appreciation:r,authorinfo:s},function(t){console.log(t)}),c.html("添加成功！")):c.html("条件不充分！")});var t=$("a.deleteArticleLink");for(i=0;t.length>i;i++)(function(e){t.eq(e).on("click",function(){var t=$(this);$.getJSON("/deletepoem",{id:t.attr("id")},function(e){var n=e.num;1===n&&t.parent().parent().remove()})})})(i);$(".btn-update-poem").on("click",function(){var t=$(this),e=$(".article-title").val(),n=new Date,a=Date.parse(n),i=$(".article-type").find("option:selected").val(),l=$("#elm1").val(),o=$(".article-author").val(),c=t.siblings(".notice-span"),r=$("#elm2").val(),s=$("#elm3").val(),m=$(".article-title").attr("article-id");e.length>1&&l.length>1&&o.length>1&&r.length>1&&s.length>1?(c.html(""),$.getJSON("/updatepoem",{_id:m,title:e,content:l,time:n.toLocaleString(),type:i,parse:a,author:o,appreciation:r,authorinfo:s},function(t){console.log(t)}),c.html("更新成功！")):c.html("条件不充分！")});var e=$("select.poem-type").attr("data-selected");$("select.poem-type").find("option[value="+e+"]").attr("selected","selected")});